function connectDevice(ip) {
            addLog('info', '正在连接设备: ' + ip);
            apiPost('/api/v1/devices/' + ip + '/connect', null).then(function(result) {
                if (result && result.success) {
                    showToast('success', '设备已连接: ' + ip);
                    addLog('success', result.message || '连接成功');
                    refreshDevices();
                    refreshPtzDeviceList();
                    refreshAdvancedDeviceSelectors();
                    // --- v3: Update global window.connectedDevice ---
                    var dev = allDevices.find(function(d) { return d.ip === ip; });
                    if (dev) {
                        window.connectedDevice = window.connectedDevice = {
                            ip: dev.ip, model: dev.model || '', name: dev.name || dev.device_name || '',
                            mac: dev.mac || '', username: 'admin', password: '', port: 80, online: true
                        };
                        addLog('info', '已记住连接设备: ' + window.connectedDevice.ip);
                        // WASM SDK login - user clicked Connect
                        if (window.clickLogin2) { window.clickLogin2(); }
                    }
                } else if (result && result.message && result.message.indexOf('凭据') >= 0) {
                    var username = prompt("\u8bf7\u8f93\u5165\u7528\u6237\u540d:", "admin");
                    if (!username) return;
                    var password = prompt("\u8bf7\u8f93\u5165\u5bc6\u7801:");
                    if (!password) return;
                    apiPost("/api/v1/devices/" + ip + "/connect", { username: username, password: password }).then(function(result) {
                        if (result && result.success) {
                            showToast("success", "\u5df2\u8fde\u63a5: " + ip);
                            addLog("success", result.message || "\u8fde\u63a5\u6210\u529f");
                            refreshDevices(); refreshPtzDeviceList(); refreshAdvancedDeviceSelectors();
                            var dev = allDevices.find(function(d) { return d.ip === ip; });
                            if (dev) window.connectedDevice = { ip: dev.ip, model: dev.model||"", name: dev.name||dev.device_name||"", mac: dev.mac||"", username: username, password: password, port: 80, online: true };
                        } else showToast("error", result ? result.message : "\u8fde\u63a5\u5931\u8d25");
                    }).catch(function(e) { showToast("error", "\u8fde\u63a5\u5f02\u5e38: " + e.message); });
                    return;
                } else {
                    showToast('error', result ? result.message : '连接失败');
                    addLog('error', result ? result.message : '连接失败');
                }
            }).catch(function(e) {
                showToast('error', '连接异常: ' + e.message);
                addLog('error', '连接异常: ' + e.message);
            });
        }

